CREATE TABLE IF NOT EXISTS accounts (id text PRIMARY KEY, email text NOT NULL UNIQUE, enabled boolean NOT NULL DEFAULT true, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS providers (id text PRIMARY KEY, account_id text NOT NULL REFERENCES accounts(id), name text NOT NULL, base_url text NOT NULL, adapter_type text NOT NULL DEFAULT 'openai_compatible', enabled boolean NOT NULL DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(account_id,name));
CREATE TABLE IF NOT EXISTS api_keys (id text PRIMARY KEY, provider_id text NOT NULL REFERENCES providers(id), label text NOT NULL, secret_ciphertext text NOT NULL, fingerprint text NOT NULL, enabled boolean NOT NULL DEFAULT true, suspended_until timestamptz, usage_count bigint NOT NULL DEFAULT 0, last_used_at timestamptz);
CREATE TABLE IF NOT EXISTS models (id text PRIMARY KEY, api_key_id text NOT NULL REFERENCES api_keys(id), logical_name text NOT NULL, upstream_model text NOT NULL, enabled boolean NOT NULL DEFAULT true, usage_count bigint NOT NULL DEFAULT 0, last_used_at timestamptz, UNIQUE(api_key_id,logical_name));
CREATE INDEX IF NOT EXISTS idx_models_routing ON models(enabled,logical_name);
